export type WeatherCondition = {
  id: number
  main: string
  description: string
  icon: string
}

export type CurrentWeather = {
  coord: { lon: number; lat: number }
  weather: WeatherCondition[]
  main: {
    temp: number
    feels_like: number
    temp_min: number
    temp_max: number
    pressure: number
    humidity: number
  }
  wind: { speed: number; deg: number }
  clouds: { all: number }
  dt: number
  sys: { country: string; sunrise: number; sunset: number }
  name: string
}

export type ForecastEntry = {
  dt: number
  main: {
    temp: number
    feels_like: number
    temp_min: number
    temp_max: number
    pressure: number
    humidity: number
  }
  weather: WeatherCondition[]
  wind: { speed: number; deg: number }
  dt_txt: string
}

export type ForecastResponse = {
  list: ForecastEntry[]
  city: {
    name: string
    country: string
  }
}

export type DayForecast = {
  date: string
  dayName: string
  high: number
  low: number
  icon: string
  description: string
}

export type WeatherDashboardData = {
  current: CurrentWeather
  forecast: DayForecast[]
