const DEFAULT_CITY = 'new york'

export const getWeatherData = (city: string): { current: CurrentWeather; forecast: ForecastResponse } | null => {
  const key = city.toLowerCase().trim()
  return WEATHER_PRESETS[key] ?? null
}

export const getAvailableCities = (): string[] => Object.keys(WEATHER_PRESETS)

export const getDefaultCity = (): string => DEFAULT_CITY

export const generatePlaceholderData = (cityName: string): { current: CurrentWeather; forecast: ForecastResponse } => {
  const baseTemp = Math.floor(Math.random() * 25) + 5
  const now = Math.floor(Date.now() / 1000)
  const daySeconds = 86400

  const conditions: Array<{ id: number; main: string; description: string; icon: string }> = [
    { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
    { id: 801, main: 'Clouds', description: 'few clouds', icon: '02d' },
    { id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' },
    { id: 500, main: 'Rain', description: 'light rain', icon: '10d' },
    { id: 804, main: 'Clouds', description: 'overcast clouds', icon: '04d' },
  ]

  const randomCondition = () => conditions[Math.floor(Math.random() * conditions.length)]

  return {
    current: {
      coord: { lon: 0, lat: 0 },
      weather: [randomCondition()],
      main: {
        temp: baseTemp,
        feels_like: baseTemp - 1,
        temp_min: baseTemp - 2,
        temp_max: baseTemp + 2,
        pressure: 1013,
        humidity: Math.floor(Math.random() * 40) + 40,
      },
      wind: { speed: Math.round(Math.random() * 8 * 10) / 10, deg: Math.floor(Math.random() * 360) },
      clouds: { all: Math.floor(Math.random() * 100) },
      dt: now,
      sys: { country: '??', sunrise: now - 21600, sunset: now + 21600 },
      name: cityName,
    },
    forecast: {
      list: Array.from({ length: 5 }, (_, i) => {
        const dayTemp = baseTemp + Math.floor(Math.random() * 10) - 5
        const dt = now + daySeconds * (i + 1)
        const date = new Date(dt * 1000)
        return {
          dt,
          main: {
            temp: dayTemp,
            feels_like: dayTemp - 1,
            temp_min: dayTemp - 3,
            temp_max: dayTemp + 3,
            pressure: 1010 + Math.floor(Math.random() * 10),
            humidity: Math.floor(Math.random() * 40) + 40,
          },
          weather: [randomCondition()],
          wind: { speed: Math.round(Math.random() * 8 * 10) / 10, deg: Math.floor(Math.random() * 360) },
          dt_txt: `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')} 12:00:00`,
        }
      }),
      city: { name: cityName, country: '??' },
    },
  }
}

import type { CurrentWeather, ForecastResponse, DayForecast, WeatherDashboardData } from './types'
import { getWeatherData, generatePlaceholderData } from './data'

const WEEKDAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

export const celsiusToFahrenheit = (c: number): number => Math.round((c * 9) / 5 + 32)

export const formatTemp = (celsius: number): string =>
  `${Math.round(celsius)}°C / ${celsiusToFahrenheit(celsius)}°F`

export const getWeatherIcon = (iconCode: string): string => {
  const iconMap: Record<string, string> = {
    '01d': '\u2600\uFE0F',  // sun
    '01n': '\uD83C\uDF19',  // moon
    '02d': '\u26C5',        // sun behind cloud
    '02n': '\u2601\uFE0F',  // cloud
    '03d': '\u2601\uFE0F',  // cloud
    '03n': '\u2601\uFE0F',  // cloud
    '04d': '\u2601\uFE0F',  // cloud
    '04n': '\u2601\uFE0F',  // cloud
    '09d': '\uD83C\uDF27\uFE0F', // rain
    '09n': '\uD83C\uDF27\uFE0F', // rain
    '10d': '\uD83C\uDF26\uFE0F', // sun behind rain cloud
    '10n': '\uD83C\uDF27\uFE0F', // rain
    '11d': '\u26C8\uFE0F',  // thunder
    '11n': '\u26C8\uFE0F',  // thunder
    '13d': '\u2744\uFE0F',  // snowflake
    '13n': '\u2744\uFE0F',  // snowflake
    '50d': '\uD83C\uDF2B\uFE0F', // fog
    '50n': '\uD83C\uDF2B\uFE0F', // fog
  }
  return iconMap[iconCode] ?? '\u2601\uFE0F'
}

export const windDirection = (deg: number): string => {
  const dirs = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW']
  return dirs[Math.round(deg / 45) % 8]
}

const parseForecast = (forecast: ForecastResponse): DayForecast[] =>
  forecast.list.map((entry) => {
    const date = new Date(entry.dt * 1000)
    return {
      date: entry.dt_txt.split(' ')[0],
      dayName: WEEKDAYS[date.getDay()],
      high: Math.round(entry.main.temp_max),
      low: Math.round(entry.main.temp_min),
      icon: entry.weather[0]?.icon ?? '03d',
      description: entry.weather[0]?.description ?? 'unknown',
    }
  })

export const fetchWeather = (city: string): WeatherDashboardData | null => {
  const data = getWeatherData(city)
  if (!data) {
    const generated = generatePlaceholderData(city)
    return {
      current: generated.current,
      forecast: parseForecast(generated.forecast),
    }
  }
  return {
    current: data.current,
    forecast: parseForecast(data.forecast),
  }
}

import { h } from 'plaited'
import type { DayForecast } from './types'

const CHART_WIDTH = 500
const CHART_HEIGHT = 200
const PADDING = { top: 20, right: 30, bottom: 40, left: 45 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

const buildPolylinePoints = (values: number[], minVal: number, maxVal: number): string => {
  const range = maxVal - minVal || 1
  return values
    .map((v, i) => {
      const x = PADDING.left + (i / (values.length - 1)) * plotWidth
      const y = PADDING.top + plotHeight - ((v - minVal) / range) * plotHeight
      return `${x},${y}`
    })
    .join(' ')
}

export const renderTempChart = (forecast: DayForecast[]) => {
  const highs = forecast.map((d) => d.high)
  const lows = forecast.map((d) => d.low)
  const allTemps = [...highs, ...lows]
  const minTemp = Math.min(...allTemps) - 2
  const maxTemp = Math.max(...allTemps) + 2

  const highPoints = buildPolylinePoints(highs, minTemp, maxTemp)
  const lowPoints = buildPolylinePoints(lows, minTemp, maxTemp)

  const range = maxTemp - minTemp || 1
  const yTicks = Array.from({ length: 5 }, (_, i) => {
    const val = minTemp + (range * i) / 4
    const y = PADDING.top + plotHeight - (i / 4) * plotHeight
    return { val: Math.round(val), y }
  })

  return h(
    'div',
    {
      style: {
        background: '#f8fafc',
        borderRadius: '12px',
        padding: '16px',
        marginTop: '16px',
      },
    },
    h('h3', { style: { margin: '0 0 12px', fontSize: '16px', color: '#334155' } }, 'Temperature Trend'),
    h(
      'svg',
      {
        viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
        style: { width: '100%', maxWidth: `${CHART_WIDTH}px`, height: 'auto' },
      },
      // grid lines
      ...yTicks.map(({ y }) =>
        h('line', {
          x1: String(PADDING.left),
          y1: String(y),
          x2: String(CHART_WIDTH - PADDING.right),
          y2: String(y),
          stroke: '#e2e8f0',
          'stroke-width': '1',
        })
      ),
      // y-axis labels
      ...yTicks.map(({ val, y }) =>
        h(
          'text',
          {
            x: String(PADDING.left - 8),
            y: String(y + 4),
            'text-anchor': 'end',
            'font-size': '11',
            fill: '#64748b',
          },
          `${val}°`
        )
      ),
      // x-axis labels
      ...forecast.map((d, i) => {
        const x = PADDING.left + (i / (forecast.length - 1)) * plotWidth
        return h(
          'text',
          {
            x: String(x),
            y: String(CHART_HEIGHT - 8),
            'text-anchor': 'middle',
            'font-size': '11',
            fill: '#64748b',
          },
          d.dayName
        )
      }),
      // high line
      h('polyline', {
        points: highPoints,
        fill: 'none',
        stroke: '#ef4444',
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
      }),
      // low line
      h('polyline', {
        points: lowPoints,
        fill: 'none',
        stroke: '#3b82f6',
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
      }),
      // high dots
      ...highs.map((v, i) => {
        const x = PADDING.left + (i / (highs.length - 1)) * plotWidth
        const y = PADDING.top + plotHeight - ((v - minTemp) / range) * plotHeight
        return h('circle', { cx: String(x), cy: String(y), r: '4', fill: '#ef4444' })
      }),
      // low dots
      ...lows.map((v, i) => {
        const x = PADDING.left + (i / (lows.length - 1)) * plotWidth
        const y = PADDING.top + plotHeight - ((v - minTemp) / range) * plotHeight
        return h('circle', { cx: String(x), cy: String(y), r: '4', fill: '#3b82f6' })
      }),
      // legend
      h('circle', { cx: String(CHART_WIDTH - 100), cy: '12', r: '4', fill: '#ef4444' }),
      h('text', { x: String(CHART_WIDTH - 92), y: '16', 'font-size': '11', fill: '#64748b' }, 'High'),
      h('circle', { cx: String(CHART_WIDTH - 55), cy: '12', r: '4', fill: '#3b82f6' }),
      h('text', { x: String(CHART_WIDTH - 47), y: '16', 'font-size': '11', fill: '#64748b' }, 'Low')
    )
  )
}

