import { createSSR } from 'plaited'
import { fetchWeather } from './weather'
import { getAvailableCities, getDefaultCity } from './data'
import { renderDashboard, renderError } from './render'
import type { WeatherDashboardData } from './types'

export type WeatherRequest = {
  city?: string
}

export const getWeatherDashboard = (request?: WeatherRequest): string => {
  const city = request?.city?.trim() || getDefaultCity()
  const availableCities = getAvailableCities()

  const data = fetchWeather(city)
  if (!data) {
    const template = renderError(`Could not load weather data for "${city}".`, availableCities)
    return createSSR(template)
  }

  const template = renderDashboard(data, availableCities)
  return createSSR(template)
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const city = url.searchParams.get('city') ?? undefined

  const html = getWeatherDashboard({ city })

  const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f1f5f9; min-height: 100vh; padding: 20px; }
  </style>
</head>
<body>
  ${html}
  <script>
    document.querySelector('form')?.addEventListener('submit', (e) => {
      e.preventDefault();
      const input = e.target.querySelector('input[name="city"]');
      if (input?.value) {
        window.location.search = '?city=' + encodeURIComponent(input.value);
      }
    });
  </script>
</body>
</html>`

  return new Response(page, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

// Bun server entry point
if (import.meta.main) {
  const port = Number(Bun.env.PORT) || 3000
  Bun.serve({
    port,
    fetch: handleRequest,
  })
  console.log(`Weather Dashboard running at http://localhost:${port}`)
}
